import React, { useState, useEffect } from 'react';

function generateToken(length = 32) {
  let result = '';
  const characters = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
  for (let i = 0; i < length; i++) {
    result += characters.charAt(Math.floor(Math.random() * characters.length));
  }
  return result;
}

const App = () => {
  const [token, setToken] = useState('');

  useEffect(() => {
    if (!window.sessionStorage.getItem('session_token')) {
      const newToken = generateToken();
      window.sessionStorage.setItem('session_token', newToken);
      setToken(newToken);
    } else {
      setToken(window.sessionStorage.getItem('session_token'));
    }
  }, []);

  return (
    <View>
      <Text>Session Token: {token}</Text>
      <Button title="Regenerate Token" onPress={() => {
        const newToken = generateToken();
        window.sessionStorage.setItem('session_token', newToken);
        setToken(newToken);
      }} />
    </View>
  );
};

export default App;